export function initialize(sentinel, dotNetRef) {
    const observer = new IntersectionObserver(entries => {
        if (entries[0].isIntersecting) {
            dotNetRef.invokeMethodAsync('OnSentinelVisible');
        }
    }, { rootMargin: '200px' });

    observer.observe(sentinel);

    return { dispose: () => observer.disconnect() };
}

@typeparam TItem
@implements IAsyncDisposable
@inject IJSRuntime JS

<div class="infinite-scroll-container">
    @foreach (var item in Items)
    {
        @ChildContent(item)
    }

    @if (HasMore)
    {
        <div @ref="sentinelRef" class="infinite-scroll-sentinel">
            @if (isLoading)
            {
                <div class="infinite-scroll-spinner"></div>
            }
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired]
    public IReadOnlyList<TItem> Items { get; set; } = [];

    [Parameter]
    public bool HasMore { get; set; }

    [Parameter, EditorRequired]
    public EventCallback OnLoadMore { get; set; }

    [Parameter, EditorRequired]
    public RenderFragment<TItem> ChildContent { get; set; } = default!;

    private ElementReference sentinelRef;
    private IJSObjectReference? module;
    private IJSObjectReference? observerHandle;
    private DotNetObjectReference<InfiniteScrollList<TItem>>? dotNetRef;
    private bool isLoading;
    private bool observerInitialized;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (HasMore && !observerInitialized)
        {
            await InitializeObserver();
        }
        else if (!HasMore && observerInitialized)
        {
            await DisposeObserver();
        }
    }

    private async Task InitializeObserver()
    {
        module ??= await JS.InvokeAsync<IJSObjectReference>(
            "import", "./js/infinite-scroll.js");

        dotNetRef ??= DotNetObjectReference.Create(this);
        observerHandle = await module.InvokeAsync<IJSObjectReference>(
            "initialize", sentinelRef, dotNetRef);
        observerInitialized = true;
    }

    [JSInvokable]
    public async Task OnSentinelVisible()
    {
        if (isLoading || !HasMore) return;

        isLoading = true;
        StateHasChanged();

        await OnLoadMore.InvokeAsync();

        isLoading = false;
        StateHasChanged();
    }

    private async Task DisposeObserver()
    {
        if (observerHandle is not null)
        {
            await observerHandle.InvokeVoidAsync("dispose");
            observerHandle = null;
        }
        observerInitialized = false;
    }

    public async ValueTask DisposeAsync()
    {
        await DisposeObserver();
        dotNetRef?.Dispose();
        if (module is not null)
        {
            await module.DisposeAsync();
        }
    }
}

.infinite-scroll-container {
    overflow-y: auto;
}

.infinite-scroll-sentinel {
    display: flex;
    justify-content: center;
    padding: 1rem;
}

.infinite-scroll-spinner {
    width: 2rem;
    height: 2rem;
    border: 3px solid rgba(0, 0, 0, 0.1);
    border-top-color: #0d6efd;
    border-radius: 50%;
    animation: spin 0.8s linear infinite;
}

@keyframes spin {
    to { transform: rotate(360deg); }
}

